cat > /tmp/block_icmp.sh << 'EOF'
> #!/bin/bash
> # Block outbound ICMP and rate-limit any remaining allowed ICMP to 10pps
> nft flush ruleset
> nft add table inet filter
> nft 'add chain inet filter input { type filter hook input priority 0; policy acccept; }'
> nft 'add chain inet filter forward { type filter hook forward priority 0; policcy accept; }'
> nft 'add chain inet filter output { type filter hook output priority 0; policy  accept; }'
> # drop outbound ICMP echoes
> nft add rule inet filter output ip protocol icmp icmp type echo-request drop
> # rate limit any other icmp to 10 packets per second with burst 20
> nft add rule inet filter output ip protocol icmp limit rate 10/second burst 20  packets drop
> # allow established
> nft add rule inet filter input ct state established,related accept
> nft add rule inet filter output ct state established,related accept
> EOF
0;root@UbuntuComputer: /usr/src/approot@UbuntuComputer:/usr/src/app# chmod +x /tmp/block_icmp.sh
0;root@UbuntuComputer: /usr/src/approot@UbuntuComputer:/usr/src/app# /tmp/block_icmp.sh
0;root@UbuntuComputer: /usr/src/approot@UbuntuComputer:/usr/src/app# nft list ruleset
table inet filter {
 chain input {
  type filter hook input priority filter; policy accept;
  ct state established,related accept
 }

 chain forward {
  type filter hook forward priority filter; policy accept;
 }

 chain output {
  type filter hook output priority filter; policy accept;
  ip protocol icmp icmp type echo-request drop
  ip protocol icmp limit rate 10/second burst 20 packets drop
  ct state established,related accept
 }
}
0;root@UbuntuComputer: /usr/src/approot@UbuntuComputer:/usr/src/app#
